import Image from "next/image";
import Link from "next/link";
import { notFound } from "next/navigation";
import { PriceSource } from "@prisma/client";
import { prisma } from "../../../lib/prisma";

function formatPriceFullIdr(value: bigint | null | undefined): string {
  if (!value) return "Price on request";
  return `Rp ${Number(value).toLocaleString("id-ID")} IDR`;
}

function normalizeSpecKey(value: string): string {
  return value.replace(/\s+/g, " ").trim();
}

export default async function CarDetailPage({ params }: { params: Promise<{ slug: string }> }) {
  const { slug } = await params;

  const activePriceList = await prisma.priceList.findFirst({
    where: {
      source: PriceSource.OTR_IMAGE,
      isActive: true,
    },
    orderBy: { createdAt: "desc" },
  });

  const model = await prisma.carModel.findUnique({
    where: { slug },
    include: {
      colors: {
        orderBy: { sortOrder: "asc" },
      },
      variants: {
        orderBy: { sortOrder: "asc" },
        include: {
          specs: {
            orderBy: [{ specGroup: "asc" }, { sortOrder: "asc" }],
          },
          prices: activePriceList
            ? {
                where: { priceListId: activePriceList.id },
                orderBy: { otrPrice: "asc" },
              }
            : false,
        },
      },
      prices: activePriceList
        ? {
            where: { priceListId: activePriceList.id },
            orderBy: { otrPrice: "asc" },
          }
        : false,
    },
  });

  if (!model) {
    notFound();
  }

  const compareVariants = model.variants.slice(0, 3);

  const performanceKeys = Array.from(
    new Set(
      compareVariants.flatMap((variant) =>
        variant.specs
          .filter((spec) => spec.specGroup.toUpperCase() === "PERFORMANCE")
          .map((spec) => normalizeSpecKey(spec.specKey)),
      ),
    ),
  );

  const featureKeys = Array.from(
    new Set(
      compareVariants.flatMap((variant) =>
        variant.specs
          .filter((spec) => spec.specGroup.toUpperCase() === "KEY_FEATURES")
          .map((spec) => normalizeSpecKey(spec.specKey)),
      ),
    ),
  );

  const valueByVariantAndKey = new Map<string, string>();
  for (const variant of compareVariants) {
    for (const spec of variant.specs) {
      valueByVariantAndKey.set(`${variant.id}::${normalizeSpecKey(spec.specKey)}`, spec.specValue);
    }
  }

  return (
    <main className="container mx-auto px-4 py-12 bg-white min-h-screen">
      <Link href="/" className="inline-flex items-center text-sm text-primary-suzuki hover:underline mb-6">
        Back to home
      </Link>

      <section className="mb-10">
        <h1 className="text-4xl font-suzuki-pro-headline text-foreground">{model.name}</h1>
        <p className="font-sans text-lg tracking-wide text-primary-suzuki mt-2">
          SEE WHICH {model.name.toUpperCase()} IS PERFECTLY RIGHT FOR YOU
        </p>
      </section>

      <section className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {compareVariants.map((variant, index) => {
          const fallbackColor = model.colors[index] ?? model.colors[0];
          return (
            <article key={variant.id} className="border border-gray-200 bg-white p-4 shadow-sm">
              <div className="border border-gray-200 px-3 py-2">
                <p className="text-sm font-sans uppercase text-gray-500">{model.name}</p>
                <p className="font-sans font-semibold text-foreground">{variant.name}</p>
              </div>

              <div className="relative w-full aspect-[16/9] bg-gray-100 mt-3">
                <Image
                  src={model.heroImage ?? fallbackColor?.imageUrl ?? "https://placehold.co/640x360/e5e7eb/9ca3af?text=Suzuki"}
                  alt={variant.name}
                  fill
                  className="object-contain"
                  unoptimized
                />
              </div>

              <div className="mt-3">
                <p className="text-xs font-sans uppercase text-gray-500">{fallbackColor?.name ?? "Color option"}</p>
                <p className="font-sans font-bold text-2xl text-foreground mt-1">
                  {formatPriceFullIdr(variant.prices[0]?.otrPrice)}
                </p>
                <p className="text-xs font-sans text-gray-500 mt-1">OTR D.K.I Jakarta</p>
              </div>
            </article>
          );
        })}
      </section>

      <section className="mt-10 border border-gray-200 bg-white">
        <h2 className="px-4 py-3 font-suzuki-pro-headline text-2xl border-b border-gray-200">PERFORMANCE</h2>
        <div className="overflow-x-auto">
          <table className="w-full min-w-[840px] text-sm">
            <tbody>
              {performanceKeys.map((key) => (
                <tr key={key} className="border-b border-gray-100">
                  <td className="px-4 py-3 w-72 font-sans text-gray-600">{key}</td>
                  {compareVariants.map((variant) => (
                    <td key={`${variant.id}-${key}`} className="px-4 py-3 font-sans text-foreground">
                      {valueByVariantAndKey.get(`${variant.id}::${key}`) ?? "-"}
                    </td>
                  ))}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </section>

      <section className="mt-8 border border-gray-200 bg-white">
        <h2 className="px-4 py-3 font-suzuki-pro-headline text-2xl border-b border-gray-200">KEY FEATURES</h2>
        <div className="overflow-x-auto">
          <table className="w-full min-w-[840px] text-sm">
            <tbody>
              {featureKeys.map((key) => (
                <tr key={key} className="border-b border-gray-100">
                  <td className="px-4 py-3 w-72 font-sans text-gray-600">{key}</td>
                  {compareVariants.map((variant) => (
                    <td key={`${variant.id}-${key}`} className="px-4 py-3 font-sans text-foreground">
                      {valueByVariantAndKey.get(`${variant.id}::${key}`) ?? "-"}
                    </td>
                  ))}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </section>

      <section className="mt-8 border border-gray-200 bg-white p-4">
        <h2 className="font-sans font-semibold text-foreground mb-3">All Variants</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
          {model.variants.map((variant) => (
            <div key={variant.id} className="border border-gray-100 p-3">
              <p className="font-sans text-sm text-gray-700">{variant.name}</p>
              <p className="font-sans font-medium text-foreground mt-1">
                {formatPriceFullIdr(variant.prices[0]?.otrPrice)}
              </p>
            </div>
          ))}
        </div>
      </section>

      <section className="mt-8 border border-gray-200 bg-white p-4">
        <h2 className="font-sans font-semibold text-foreground mb-3">Available Colors</h2>
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-2">
          {model.colors.map((color) => (
            <div key={color.id} className="border border-gray-100 p-2">
              <div className="relative w-full aspect-video bg-gray-100 mb-2">
                <Image
                  src={color.imageUrl ?? "https://placehold.co/300x180/e5e7eb/9ca3af?text=Color"}
                  alt={color.name}
                  fill
                  className="object-cover"
                  unoptimized
                />
              </div>
              <p className="text-xs font-sans text-gray-700 line-clamp-2">{color.name}</p>
            </div>
          ))}
        </div>
      </section>
    </main>
  );
}
